from fastapi import FastAPI, BackgroundTasks
from celery import Celery
from pydantic import BaseModel
import time
import hashlib

# Celery configuration
celery_app = Celery(
    'ai_background_tasks',
    broker='redis://localhost:6379/0',
    backend='redis://localhost:6379/1'
)

celery_app.conf.update(
    task_serializer='json',
    accept_content=['json'],
    result_serializer='json',
    timezone='UTC',
    enable_utc=True,
    task_track_started=True,
    task_time_limit=300,
)

app = FastAPI(title="AI Background Applications API")

# Data models
class AIRequest(BaseModel):
    text: str
    model_type: str = "sentiment"

class TaskResponse(BaseModel):
    task_id: str
    status: str
    message: str

# Simulated AI models
def sentiment_analysis(text):
    """Simulated sentiment analysis model"""
    time.sleep(2)  # Simulate inference
    words = text.lower().split()
    positive = sum(1 for w in words if w in ['good', 'great', 'excellent', 'amazing', 'love'])
    negative = sum(1 for w in words if w in ['bad', 'terrible', 'awful', 'hate', 'poor'])

    if positive > negative:
        return {"sentiment": "positive", "score": 0.85}
    elif negative > positive:
        return {"sentiment": "negative", "score": 0.78}
    return {"sentiment": "neutral", "score": 0.65}

def text_classification(text):
    """Simulated text classification model"""
    time.sleep(1.5)
    categories = ["Technology", "Sports", "Business", "Entertainment"]
    return {"category": categories[hash(text) % 4], "confidence": 0.92}

# Celery background tasks
@celery_app.task(bind=True, name='process_ai_task')
def process_ai_task(self, text, model_type):
    """Celery task for background AI processing"""
    try:
        # Update progress
        self.update_state(state='PROCESSING', meta={'step': 'preprocessing'})
        time.sleep(0.5)

        self.update_state(state='PROCESSING', meta={'step': 'inference'})
        if model_type == "sentiment":
            result = sentiment_analysis(text)
        else:
            result = text_classification(text)

        self.update_state(state='PROCESSING', meta={'step': 'postprocessing'})
        time.sleep(0.3)

        return {"status": "completed", "result": result}
    except Exception as e:
        return {"status": "failed", "error": str(e)}

# FastAPI endpoints
@app.post("/api/ai/process", response_model=TaskResponse)
def create_ai_task(request: AIRequest, background_tasks: BackgroundTasks):
    """Submit AI task for background processing"""
    task = process_ai_task.delay(request.text, request.model_type)

    return TaskResponse(
        task_id=task.id,
        status="submitted",
        message="AI task submitted for background processing"
    )

@app.get("/api/ai/status/{task_id}")
def get_task_status(task_id: str):
    """Check status of background AI task"""
    task = celery_app.AsyncResult(task_id)

    return {
        "task_id": task_id,
        "status": task.state,
        "result": task.result if task.ready() else None,
        "info": task.info if task.info else None
    }

# Example: Trigger background processing without API
def process_in_background(text: str, model_type: str = "sentiment"):
    """Function to demonstrate background processing trigger"""
    task = process_ai_task.delay(text, model_type)
    print(f"Task submitted: {task.id}")

    # Poll for result (in real app, use webhooks or callbacks)
    while not task.ready():
        time.sleep(1)
        print("Waiting for AI processing...")

    return task.get()

# Demo execution
if __name__ == "__main__":
    # Example usage of background processing function
    print("Starting background AI processing...")
    result = process_in_background("This product is amazing and works great!", "sentiment")
    print(f"Final Result: {result}")
